{"action": "write_file", "name": "creative-workflow-dashboard", "file_path": "server.py", "file_content": "#!/usr/bin/env python3
"""
创作流水线控制面板 - Flask服务器
位置: ~/.hermes/skills/creative-workflow-dashboard/server.py
启动: python3 server.py
访问: http://localhost:8765
"""

import json
import os
import threading
import uuid
from datetime import datetime
from flask import Flask, jsonify, request, send_from_directory
from pathlib import Path

# ============================================================
# 配置
# ============================================================
BASE_DIR = Path(__file__).parent
STATE_DIR = BASE_DIR / "state"
OUTPUTS_DIR = BASE_DIR / "module_outputs"
STATIC_DIR = BASE_DIR / "static"

STATE_FILE = STATE_DIR / "workflow_state.json"
CONFIG_FILE = STATE_DIR / "config.json"

# 确保目录存在
STATE_DIR.mkdir(exist_ok=True)
OUTPUTS_DIR.mkdir(exist_ok=True)
STATIC_DIR.mkdir(exist_ok=True)

# ============================================================
# Flask App
# ============================================================
app = Flask(__name__, static_folder=str(STATIC_DIR))
app.config['JSON_AS_ASCII'] = False

# ============================================================
# 默认状态
# ============================================================
MODULES = ["A", "B", "C", "D", "E", "F", "G"]
MODULE_NAMES = {
    "A": "内容选题",
    "B": "文案创作",
    "C": "合规审查",
    "D": "视频生成",
    "E": "语音合成",
    "F": "内容组装",
    "G": "多平台发布",
}

DEFAULT_STATE = {
    "modules": {
        m: {
            "id": m,
            "name": MODULE_NAMES[m],
            "status": "idle",  # idle | running | done | error | paused
            "started_at": None,
            "completed_at": None,
            "error_message": None,
            "output_file": f"module_outputs/{m}_output.json",
            "last_input": None,
        }
        for m in MODULES
    },
    "current_module": None,
    "workflow_started_at": None,
    "workflow_completed_at": None,
    "logs": [],
}

DEFAULT_CONFIG = {
    "llm": {
        "current": "minimax",
        "available": ["minimax", "grok", "claude"],
        "models": {
            "minimax": {"name": "MiniMax-M2", "api_key": ""},
            "grok": {"name": "Grok-4", "api_key": ""},
            "claude": {"name": "Claude 3.5", "api_key": ""},
        },
    },
    "video": {
        "current": "runway",
        "available": ["runway", "supergrok", "kling", "pika"],
        "configs": {
            "runway": {"api_key": ""},
            "supergrok": {"api_key": ""},
            "kling": {"api_key": ""},
            "pika": {"api_key": ""},
        },
    },
    "audio": {
        "current": "elevenlabs",
        "available": ["elevenlabs", "cartesia", "openai"],
        "configs": {
            "elevenlabs": {"api_key": "", "voice_id": ""},
            "cartesia": {"api_key": ""},
            "openai": {"api_key": ""},
        },
    },
    "platforms": {
        "available": ["douyin", "kuaishou", "xiaohongshu", "shipinhao", "bilibili"],
        "selected": ["douyin"],
    },
}


# ============================================================
# 状态读写
# ============================================================
def load_state():
    if STATE_FILE.exists():
        with open(STATE_FILE, "r", encoding="utf-8") as f:
            return json.load(f)
    return DEFAULT_STATE.copy()


def save_state(state):
    with open(STATE_FILE, "w", encoding="utf-8") as f:
        json.dump(state, f, ensure_ascii=False, indent=2)


def load_config():
    if CONFIG_FILE.exists():
        with open(CONFIG_FILE, "r", encoding="utf-8") as�:
            return json.load(f)
    return DEFAULT_CONFIG.copy()


def save_config(config):
    with open(CONFIG_FILE, "w", encoding="utf-8") as f:
        json.dump(config, f, ensure_ascii=False, indent=2)


def get_module_output(module_id):
    output_file = OUTPUTS_DIR / f"{module_id}_output.json"
    if output_file.exists():
        with open(output_file, "r", encoding="utf-8") as f:
            return json.load(f)
    return None


def save_module_output(module_id, data):
    output_file = OUTPUTS_DIR / f"{module_id}_output.json"
    with open(output_file, "w", encoding="utf-8") as f:
        json.dump(data, f, ensure_ascii=False, indent=2)


def add_log(state, message, level="info"):
    log_entry = {
        "timestamp": datetime.now().isoformat(),
        "level": level,
        "message": message,
    }
    state["logs"].append(log_entry)
    # 保留最近100条日志
    if len(state["logs"]) > 100:
        state["logs"] = state["logs"][-100:]


# ============================================================
# 初始化状态文件
# ============================================================
if not STATE_FILE.exists():
    save_state(DEFAULT_STATE)
if not CONFIG_FILE.exists():
    save_config(DEFAULT_CONFIG)


# ============================================================
# 路由
# ============================================================

@app.route("/")
def index():
    return send_from_directory(STATIC_DIR, "dashboard.html")


@app.route("/api/state", methods=["GET"])
def get_state():
    """获取完整工作流状态"""
    state = load_state()
    # 补充各模块的最新输出
    for m in MODULES:
        state["modules"][m]["output"] = get_module_output(m)
    return jsonify(state)


@app.route("/api/config", methods=["GET"])
def get_config():
    """获取工具配置"""
    return jsonify(load_config())


@app.route("/api/config", methods=["PUT"])
def update_config():
    """更新工具配置"""
    config = load_config()
    data = request.json
    # 深度合并
    for key in data:
        if key in config:
            if isinstance(data[key], dict) and isinstance(config[key], dict):
                config[key].update(data[key])
            else:
                config[key] = data[key]
    save_config(config)
    return jsonify({"success": True, "config": config})


@app.route("/api/module/<module_id>/run", methods=["POST"])
def run_module(module_id):
    """运行指定模块"""
    if module_id not in MODULES:
        return jsonify({"error": "未知模块"}), 400

    state = load_state()
    data = request.json or {}

    # 更新状态为running
    state["modules"][module_id]["status"] = "running"
    state["modules"][module_id]["started_at"] = datetime.now().isoformat()
    state["modules"][module_id]["error_message"] = None

    # 保存输入
    input_data = data.get("input")
    state["modules"][module_id]["last_input"] = input_data
    if input_data:
        save_module_output(module_id, {"input": input_data})

    save_state(state)
    add_log(state, f"模块 {module_id} ({MODULE_NAMES[module_id]}) 开始运行", "info")

    # 在后台线程运行实际任务
    def background_task():
        try:
            # 模拟模块运行（实际会被真实模块替换）
            result = simulate_module_run(module_id, input_data, state)
            state = load_state()
            state["modules"][module_id]["status"] = "done"
            state["modules"][module_id]["completed_at"] = datetime.now().isoformat()
            if result:
                save_module_output(module_id, result)
            save_state(state)
            add_log(state, f"模块 {module_id} ({MODULE_NAMES[module_id]}) 完成", "success")
        except Exception as e:
            state = load_state()
            state["modules"][module_id]["status"] = "error"
            state["modules"][module_id]["error_message"] = str(e)
            state["modules"][module_id]["completed_at"] = datetime.now().isoformat()
            save_state(state)
            add_log(state, f"模块 {module_id} 出错: {str(e)}", "error")

    threading.Thread(target=background_task, daemon=True).start()
    return jsonify({"success": True, "module": module_id})


@app.route("/api/module/<module_id>/reset", methods=["POST"])
def reset_module(module_id):
    """重置指定模块"""
    if module_id not in MODULES:
        return jsonify({"error": "未知模块"}), 400

    state = load_state()
    state["modules"][module_id] = {
        "id": module_id,
        "name": MODULE_NAMES[module_id],
        "status": "idle",
        "started_at": None,
        "completed_at": None,
        "error_message": None,
        "output_file": f"module_outputs/{module_id}_output.json",
        "last_input": None,
    }
    # 删除输出文件
    output_file = OUTPUTS_DIR / f"{module_id}_output.json"
    if output_file.exists():
        output_file.unlink()
    save_state(state)
    add_log(state, f"模块 {module_id} ({MODULE_NAMES[module_id]}) 已重置", "info")
    return jsonify({"success": True})


@app.route("/api/module/<module_id>/output", methods=["GET"])
def get_module_output_api(module_id):
    """获取模块输出"""
    if module_id not in MODULES:
        return jsonify({"error": "未知模块"}), 400
    output = get_module_output(module_id)
    return jsonify(output or {})


@app.route("/api/module/<module_id>/input", methods=["PUT"])
def update_module_input(module_id):
    """更新模块输入（用于修改）"""
    if module_id not in MODULES:
        return jsonify({"error": "未知模块"}), 400

    data = request.json
    state = load_state()
    state["modules"][module_id]["last_input"] = data
    # 如果模块已完成，重置状态让其可重新运行
    if state["modules"][module_id]["status"] == "done":
        state["modules"][module_id]["status"] = "idle"
        state["modules"][module_id]["completed_at"] = None
    save_state(state)

    # 更新存储的输出中的input
    current_output = get_module_output(module_id) or {}
    current_output["input"] = data
    save_module_output(module_id, current_output)

    return jsonify({"success": True})


@app.route("/api/workflow/start", methods=["POST"])
def start_workflow():
    """从指定模块开始完整流程"""
    data = request.json or {}
    start_module = data.get("from", "A")
    if start_module not in MODULES:
        return jsonify({"error": "无效起始模块"}), 400

    state = load_state()
    state["workflow_started_at"] = datetime.now().isoformat()

    # 重置目标模块之后的所有模块
    start_idx = MODULES.index(start_module)
    for m in MODULES[start_idx:]:
        state["modules"][m]["status"] = "idle"
        state["modules"][m]["completed_at"] = None
        state["modules"][m]["error_message"] = None

    save_state(state)
    add_log(state, f"工作流从模块 {start_module} 开始启动", "info")

    # 启动第一个模块
    return run_module(start_module)


@app.route("/api/workflow/reset", methods=["POST"])
def reset_workflow():
    """重置整个工作流"""
    state = DEFAULT_STATE.copy()
    state["logs"] = []
    save_state(state)

    # 删除所有输出文件
    for f in OUTPUTS_DIR.glob("*_output.json"):
        f.unlink()

    add_log(state, "工作流已全部重置", "info")
    return jsonify({"success": True})


@app.route("/api/workflow/advance", methods=["POST"])
def advance_workflow():
    """将工作流推进到下一个模块"""
    state = load_state()
    data = request.json or {}

    # 找到当前未完成的第一个模块
    next_module = None
    for m in MODULES:
        if state["modules"][m]["status"] in ["idle", "running"]:
            next_module = m
            break

    if not next_module:
        # 所有模块已完成
        return jsonify({"success": False, "message": "所有模块已完成"})

    save_state(state)

    # 运行下一个模块
    input_data = data.get("input")
    if input_data:
        state["modules"][next_module]["last_input"] = input_data

    return run_module(next_module)


# ============================================================
# 模拟模块运行（实际会被真实模块替换）
# ============================================================
def simulate_module_run(module_id, input_data, state):
    """
    模拟各模块的运行逻辑。
    实际实现时会被真实的模块代码替换。
    这里返回模拟数据供前端调试用。
    """
    import time
    time.sleep(1)  # 模拟运行时间

    if module_id == "A":
        return {
            "input": input_data,
            "options": [
                {"id": "A1", "title": "为什么散户总是追涨杀跌？", "description": "用行为金融学解释散户投资误区", "type": "原理讲解", "duration": "60-90秒"},
                {"id": "A2", "title": "读懂财报只需要3分钟", "description": "用通俗语言拆解财务报表核心指标", "type": "工具教程", "duration": "90-120秒"},
                {"id": "A3", "title": "我的第一个10万是怎么存下来的", "description": "结合理财观念讲储蓄的重要性", "type": "经验分享", "duration": "45-60秒"},
                {"id": "A4", "title": "MACD是什么？到底怎么用？", "description": "技术指标原理讲解+模拟演示", "type": "概念科普", "duration": "60-90秒"},
            ],
            "selected": None,
        }

    elif module_id == "B":
        prev_output = get_module_output("A")
        selected_topic = input_data.get("selected_topic") or (prev_output.get("selected") if prev_output else None)
        return {
            "input": input_data,
            "options": [
                {
                    "id": "B1",
                    "title": "强共鸣开场",
                    "description": "「你是不是也这样？每次看到股票涨就忍不住想买，结果一买就跌...」",
                    "style": "共鸣型",
                },
                {
                    "id": "B2",
                    "title": "数据吸引",
                    "description": "「90%的散户都在犯同一个错误，今天我用3分钟告诉你是什么。」",
                    "style": "数据型",
                },
                {
                    "id": "B3",
                    "title": "故事引入",
                    "description": "「我一个朋友，去年听消息炒股，亏了30万...他的经历让我彻底明白了...」",
                    "style": "故事型",
                },
            ],
            "selected": None,
        }

    elif module_id == "C":
        return {
            "input": input_data,
            "passed": True,
            "issues": [],
            "warnings": [
                {"line": "第3段", "text": "「保证赚钱」", "suggestion": "删除绝对化表述"},
            ],
            "summary": "文案基本符合合规要求，有1处轻微风险表述已标注",
            "risk_score": 15,  # 0-100, 越高越危险
        }

    elif module_id == "D":
        return {
            "input": input_data,
            "status": "generated",
            "file": f"/outputs/video_{uuid.uuid4().hex[:8]}.mp4",
            "thumbnail": None,
            "duration": input_data.get("duration", "60s") if input_data else "60s",
            "style": "简洁科普",
        }

    elif module_id == "E":
        return {
            "input": input_data,
            "status": "generated",
            "file": f"/outputs/audio_{uuid.uuid4().hex[:8]}.mp3",
            "duration": input_data.get("duration", "60s") if input_data else "60s",
            "voice": "克隆声音",
        }

    elif module_id == "F":
        return {
            "input": input_data,
            "status": "assembled",
            "file": f"/outputs/final_{uuid.uuid4().hex[:8]}.mp4",
            "duration": "65s",
            "has_subtitle": True,
            "has_music": True,
        }

    elif module_id == "G":
        return {
            "input": input_data,
            "results": [
                {"platform": "douyin", "status": "published", "video_id": f"dy_{uuid.uuid4().hex[:8]}", "url": "#"},
            ],
        }

    return {}


# ============================================================
# 启动
# ============================================================
if __name__ == "__main__":
    print("=" * 50)
    print("创作流水线控制面板")
    print("=" * 50)
    print(f"访问地址: http://localhost:8765")
    print(f"API文档:  http://localhost:8765/api/state")
    print("按 Ctrl+C 停止服务器")
    print("=" * 50)
    app.run(host="0.0.0.0", port=8765, debug=False)
"}

