@app.route("/")
def index():
    return send_from_directory(STATIC_DIR, "dashboard.html")


@app.route("/api/state", methods=["GET"])
def get_state():
    state = load_state()
    for m in MODULES:
        state["modules"][m]["output"] = get_module_output(m)
    return jsonify(state)


@app.route("/api/config", methods=["GET"])
def get_config():
    return jsonify(load_config())


@app.route("/api/config", methods=["PUT"])
def update_config():
    cfg = load_config()
    data = request.json
    for key in data:
        if key in cfg:
            if isinstance(data[key], dict) and isinstance(cfg[key], dict):
                cfg[key].update(data[key])
            else:
                cfg[key] = data[key]
    save_config(cfg)
    return jsonify({"success": True, "config": cfg})


@app.route("/api/module/<module_id>/run", methods=["POST"])
def run_module(module_id):
    if module_id not in MODULES:
        return jsonify({"error": "未知模块"}), 400

    state = load_state()
    data = request.json or {}

    state["modules"][module_id]["status"] = "running"
    state["modules"][module_id]["started_at"] = datetime.now().isoformat()
    state["modules"][module_id]["error_message"] = None

    input_data = data.get("input")
    state["modules"][module_id]["last_input"] = input_data
    if input_data:
        save_module_output(module_id, {"input": input_data})

    save_state(state)
    add_log(state, f"模块 {module_id} ({MODULE_NAMES[module_id]}) 开始运行", "info")

    def background_task():
        try:
            result = simulate_module_run(module_id, input_data, state)
            st = load_state()
            st["modules"][module_id]["status"] = "done"
            st["modules"][module_id]["completed_at"] = datetime.now().isoformat()
            if result:
                save_module_output(module_id, result)
            save_state(st)
            add_log(st, f"模块 {module_id} ({MODULE_NAMES[module_id]}) 完成", "success")
        except Exception as e:
            st = load_state()
            st["modules"][module_id]["status"] = "error"
            st["modules"][module_id]["error_message"] = str(e)
            st["modules"][module_id]["completed_at"] = datetime.now().isoformat()
            save_state(st)
            add_log(st, f"模块 {module_id} 出错: {str(e)}", "error")

    threading.Thread(target=background_task, daemon=True).start()
    return jsonify({"success": True, "module": module_id})


@app.route("/api/module/<module_id>/reset", methods=["POST"])
def reset_module(module_id):
    if module_id not in MODULES:
        return jsonify({"error": "未知模块"}), 400

    state = load_state()
    state["modules"][module_id] = {
        "id": module_id,
        "name": MODULE_NAMES[module_id],
        "status": "idle",
        "started_at": None,
        "completed_at": None,
        "error_message": None,
        "output_file": f"module_outputs/{module_id}_output.json",
        "last_input": None,
    }
    output_file = OUTPUTS_DIR / f"{module_id}_output.json"
    if output_file.exists():
        output_file.unlink()
    save_state(state)
    add_log(state, f"模块 {module_id} ({MODULE_NAMES[module_id]}) 已重置", "info")
    return jsonify({"success": True})


@app.route("/api/module/<module_id>/output", methods=["GET"])
def get_module_output_api(module_id):
    if module_id not in MODULES:
        return jsonify({"error": "未知模块"}), 400
    output = get_module_output(module_id)
    return jsonify(output or {})


@app.route("/api/module/<module_id>/input", methods=["PUT"])
def update_module_input(module_id):
    if module_id not in MODULES:
        return jsonify({"error": "未知模块"}), 400

    data = request.json
    state = load_state()
    state["modules"][module_id]["last_input"] = data
    if state["modules"][module_id]["status"] == "done":
        state["modules"][module_id]["status"] = "idle"
        state["modules"][module_id]["completed_at"] = None
    save_state(state)

    current_output = get_module_output(module_id) or {}
    current_output["input"] = data
    save_module_output(module_id, current_output)

    return jsonify({"success": True})


@app.route("/api/workflow/start", methods=["POST"])
def start_workflow():
    data = request.json or {}
    start_module = data.get("from", "A")
    if start_module not in MODULES:
        return jsonify({"error": "无效起始模块"}), 400

    state = load_state()
    state["workflow_started_at"] = datetime.now().isoformat()

    start_idx = MODULES.index(start_module)
    for m in MODULES[start_idx:]:
        state["modules"][m]["status"] = "idle"
        state["modules"][m]["completed_at"] = None
        state["modules"][m]["error_message"] = None

    save_state(state)
    add_log(state, f"工作流从模块 {start_module} 开始启动", "info")
    return run_module(start_module)


@app.route("/api/workflow/reset", methods=["POST"])
def reset_workflow():
    state = DEFAULT_STATE.copy()
    state["logs"] = []
    save_state(state)

    for f in OUTPUTS_DIR.glob("*_output.json"):
        f.unlink()

    add_log(state, "工作流已全部重置", "info")
    return jsonify({"success": True})


