            <div class="left-panel">
                <div class="card">
                    <div class="card-title">
                        <span class="dot"></span>
                        模块详情
                    </div>
                    <div id="module-detail" class="module-detail"></div>
                    <div id="module-empty" class="empty-state">
                        <div class="icon">📋</div>
                        <p>点击上方模块查看详情</p>
                    </div>
                </div>
            </div>

            <!-- Right Sidebar -->
            <div class="sidebar-right">

                <!-- Stage Progress -->
                <div class="card">
                    <div class="card-title">📊 进度总览</div>
                    <div id="stage-list" class="stage-list"></div>
                </div>

                <!-- Tool Config -->
                <div class="card">
                    <div class="card-title">⚙️ 工具配置</div>
                    <div class="config-grid">
                        <div class="config-item">
                            <label>LLM 模型</label>
                            <select id="cfg-llm" onchange="updateConfig('llm', this.value)"></select>
                        </div>
                        <div class="config-item">
                            <label>视频生成</label>
                            <select id="cfg-video" onchange="updateConfig('video', this.value)"></select>
                        </div>
                        <div class="config-item">
                            <label>语音合成</label>
                            <select id="cfg-audio" onchange="updateConfig('audio', this.value)"></select>
                        </div>
                    </div>
                </div>

                <!-- Platform Selection -->
                <div class="card">
                    <div class="card-title">📡 发布平台</div>
                    <div id="platform-list" class="platform-grid"></div>
                </div>

                <!-- Logs -->
                <div class="card">
                    <div class="card-title">📋 运行日志</div>
                    <div id="log-panel" class="log-panel"></div>
                </div>
            </div>
        </div>
    </div>

<script>
const MODULE_NAMES = {A:'内容选题',B:'文案创作',C:'合规审查',D:'视频生成',E:'语音合成',F:'内容组装',G:'多平台发布'};
const MODULES = ['A','B','C','D','E','F','G'];
const PLATFORM_NAMES = {douyin:'抖音',kuaishou:'快手',xiaohongshu:'小红书',shipinhao:'视频号',bilibili:'B站'};

let state = {};
let config = {};
let selectedModule = null;
let selectedOptions = {A: null, B: null};

// ============================================================
// API
// ============================================================
async function fetchState() {
    const r = await fetch('/api/state');
    return r.json();
}
async function fetchConfig() {
    const r = await fetch('/api/config');
    return r.json();
}
async function runModule(id, input) {
    await fetch(`/api/module/${id}/run`, {method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({input})});
}
async function resetModule(id) {
    await fetch(`/api/module/${id}/reset`, {method:'POST'});
}
async function updateModuleInput(id, input) {
    await fetch(`/api/module/${id}/input`, {method:'PUT', headers:{'Content-Type':'application/json'}, body: JSON.stringify(input)});
}
async function updateConfigKey(key, value) {
    await fetch('/api/config', {method:'PUT', headers:{'Content-Type':'application/json'}, body: JSON.stringify({[key]: {current: value}})});
}
async function resetWorkflow() {
    await fetch('/api/workflow/reset', {method:'POST'});
}

// ============================================================
// Render
// ============================================================
function renderPipeline(state) {
    const container = document.getElementById('pipeline');
    container.innerHTML = MODULES.map(id => {
        const m = state.modules[id];
        const isActive = selectedModule === id;
        return `
        <div class="pipeline-item ${isActive ? 'active' : ''}" onclick="selectModule('${id}')">
            <div class="module-id">模块 ${id}</div>
            <div class="module-name">${m.name}</div>
            <span class="status-badge status-${m.status}">${statusLabel(m.status)}</span>
        </div>`;
    }).join('');
}

function renderStageList(state) {
    const container = document.getElementById('stage-list');
    let foundCurrent = false;
    container.innerHTML = MODULES.map(id => {
        const m = state.modules[id];
        let cls = 'pending';
        let label = m.name;
        if (m.status === 'done') cls = 'done';
        else if (m.status === 'running') { cls = 'current'; foundCurrent = true; }
        else if (m.status === 'error') cls = 'error';
        if (m.completed_at && !foundCurrent) label += ' ✓';

        let time = '';
        if (m.completed_at) time = m.completed_at.split('T')[1].slice(0,8);
        else if (m.started_at) time = m.started_at.split('T')[1].slice(0,8);

        return `
        <div class="stage-item" onclick="selectModule('${id}')">
            <div class="stage-num ${cls}">${id}</div>
            <div class="stage-info">
                <div class="stage-name">${label}</div>
                <div class="stage-time">${time}</div>
            </div>
        </div>`;
    }).join('');
}

function renderConfig(cfg) {
    const llmSel = document.getElementById('cfg-llm');
    const vidSel = document.getElementById('cfg-video');
    const audSel = document.getElementById('cfg-audio');

    llmSel.innerHTML = cfg.llm.available.map(k => `<option value="${k}">${cfg.llm.models[k].name}</option>`).join('');
    vidSel.innerHTML = cfg.video.available.map(k => `<option value="${k}">${k}</option>`).join('');
    audSel.innerHTML = cfg.audio.available.map(k => `<option value="${k}">${k}</option>`).join('');

    llmSel.value = cfg.llm.current;
    vidSel.value = cfg.video.current;
    audSel.value = cfg.audio.current;
}

function renderPlatforms(cfg) {
    const container = document.getElementById('platform-list');
    container.innerHTML = cfg.platforms.available.map(p => {
        const sel = cfg.platforms.selected.includes(p);
        return `<div class="platform-chip ${sel ? 'selected' : ''}" onclick="togglePlatform('${p}')">${PLATFORM_NAMES[p]}</div>`;
    }).join('');
}

function renderLogs(logs) {
    const panel = document.getElementById('log-panel');
    if (!logs || logs.length === 0) {
        panel.innerHTML = '<div style="color:var(--text-dim);font-size:12px;text-align:center;padding:20px;">暂无日志</div>';
        return;
    }
    panel.innerHTML = logs.slice(-30).reverse().map(log => {
        const t = log.timestamp.split('T')[1].slice(0,8);
        return `<div class="log-entry ${log.level}"><span class="time">${t}</span><span class="msg">${log.message}</span></div>`;
    }).join('');
}

function renderModuleDetail(id, output) {
    const detail = document.getElementById('module-detail');
    const empty = document.getElementById('module-empty');
    const m = state.modules[id];

    if (!m || m.status === 'idle') {
        detail.classList.remove('active');
        empty.style.display = 'block';
        return;
    }

    empty.style.display = 'none';
    detail.classList.add('active');

    let html = `
    <div class="module-header">
        <h3>模块 ${id} — ${MODULE_NAMES[id]}</h3>
        <div class="actions">
            ${m.status === 'done' ? `<button class="btn" onclick="resetModule('${id}')">重置</button>` : ''}
            ${m.status === 'idle' || m.status === 'done' || m.status === 'error' ? `<button class="btn btn-primary" onclick="runModuleUI('${id}')">运行</button>` : ''}
            ${m.status === 'running' ? `<button class="btn" disabled>运行中...</button>` : ''}
        </div>
    </div>`;

    if (id === 'A' && output) {
        // 选题选项
        html += `<div class="options-list">`;
        (output.options || []).forEach(opt => {
            const sel = selectedOptions.A === opt.id;
            html += `
            <div class="option-item ${sel ? 'selected' : ''}" onclick="selectOption('A','${opt.id}')">
                <div class="option-title">${opt.title}</div>
                <div class="option-desc">${opt.description}</div>
                <div class="option-meta">${opt.type} · ${opt.duration}</div>
            </div>`;
        });
        html += `</div>`;
        if (selectedOptions.A) {
            html += `<div style="margin-top:12px;"><button class="btn btn-primary" onclick="confirmAndAdvance('A')">确认选题 →</button></div>`;
        }

    } else if (id === 'B' && output) {
        // 文案选项
        html += `<div class="options-list">`;
        (output.options || []).forEach(opt => {
            const sel = selectedOptions.B === opt.id;
            html += `
            <div class="option-item ${sel ? 'selected' : ''}" onclick="selectOption('B','${opt.id}')">
                <div class="option-title">${opt.title}</div>
                <div class="option-desc">${opt.description}</div>
                <div class="option-meta">风格: ${opt.style}</div>
            </div>`;
        });
        html += `</div>`;
        if (selectedOptions.B) {
            html += `<div style="margin-top:12px;"><button class="btn btn-primary" onclick="confirmAndAdvance('B')">确认文案方向 →</button></div>`;
        }

    } else if (id === 'C' && output) {
        // 合规审查
        const risk = output.risk_score || 0;
        const riskColor = risk < 30 ? 'var(--success)' : risk < 60 ? 'var(--warning)' : 'var(--error)';
        html += `
        <div class="compliance-summary ${output.passed ? 'compliance-pass' : 'compliance-fail'}">
            <div class="score" style="color:${riskColor}">${risk}</div>
            <div class="label">风险评分 (0=安全, 100=危险)</div>
            <div style="margin-top:8px;font-size:13px;">${output.summary || ''}</div>
        </div>`;
        if (output.issues && output.issues.length) {
            html += `<div style="margin-bottom:8px;font-size:13px;font-weight:600;">❌ 必须修改</div>`;
            output.issues.forEach(iss => {
                html += `<div class="issue-item">${iss.line || ''}: ${iss.text} → ${iss.suggestion}</div>`;
            });
        }
        if (output.warnings && output.warnings.length) {
            html += `<div style="margin-bottom:8px;font-size:13px;font-weight:600;">⚠️ 建议修改</div>`;
            output.warnings.forEach(w => {
                html += `<div class="warning-item">${w.line || ''}: ${w.text} → ${w.suggestion}</div>`;
            });
        }
        if (output.passed && (!output.issues || output.issues.length === 0)) {
            html += `<button class="btn btn-primary" onclick="confirmAndAdvance('C')">通过 →</button>`;
        } else {
            html += `<button class="btn" onclick="runModuleUI('C')">重新审查</button>`;
        }

    } else if (id === 'D' && output) {
        // 视频生成
        if (output.status === 'generated') {
            html += `
            <div class="file-output">
                <div class="file-icon">🎬</div>
                <div class="file-info">
                    <div class="filename">${output.file}</div>
                    <div class="filesize">${output.duration} · ${output.style}</div>
                </div>
            </div>
            <div style="margin-top:12px;"><button class="btn btn-primary" onclick="confirmAndAdvance('D')">确认视频 →</button></div>`;
        } else {
            html += `<div style="color:var(--text-dim);text-align:center;padding:30px;">正在生成中...</div>`;
        }

    } else if (id === 'E' && output) {
        // 语音
        if (output.status === 'generated') {
            html += `
            <div class="file-output">
                <div class="file-icon">🎙️</div>
                <div class="file-info">
                    <div class="filename">${output.file}</div>
                    <div class="filesize">${output.duration} · ${output.voice}</div>
                </div>
            </div>
            <div style="margin-top:12px;"><button class="btn btn-primary" onclick="confirmAndAdvance('E')">确认音频 →</button></div>`;
        } else {
            html += `<div style="color:var(--text-dim);text-align:center;padding:30px;">正在生成中...</div>`;
        }

    } else if (id === 'F' && output) {
        // 组装
        if (output.status === 'assembled') {
            html += `
            <div class="file-output">
                <div class="file-icon">🎞️</div>
                <div class="file-info">
                    <div class="filename">${output.file}</div>
                    <div class="filesize">${output.duration}${output.has_subtitle ? ' · 有字幕' : ''}${output.has_music ? ' · 有配乐' : ''}</div>
                </div>
            </div>
            <div style="margin-top:12px;"><button class="btn btn-primary" onclick="confirmAndAdvance('F')">确认成片 →</button></div>`;
        }

    } else if (id === 'G' && output) {
        // 发布
        (output.results || []).forEach(r => {
            html += `
            <div class="file-output">
                <div class="file-icon">${r.status === 'published' ? '✅' : '⏳'}</div>
                <div class="file-info">
                    <div class="filename">${PLATFORM_NAMES[r.platform] || r.platform}</div>
                    <div class="filesize">${r.status}${r.url !== '#' ? ' · ' + r.url : ''}</div>
                </div>
            </div>`;
        });
    }

    if (m.status === 'running') {
        html += `<div style="margin-top:16px;text-align:center;"><span class="running-indicator">●</span> 运行中...</div>`;
    }
    if (m.status === 'error') {
        html += `<div style="margin-top:16px;color:var(--error);font-size:13px;">❌ 错误: ${m.error_message || '未知错误'}</div>`;
    }

    detail.innerHTML = html;
}

function statusLabel(s) {
    return {idle:'待启动',running:'进行中',done:'已完成',error:'错误',paused:'暂停'}[s] || s;
}

// ============================================================
// Actions
// ============================================================
async function selectModule(id) {
    selectedModule = id;
    renderPipeline(state);
    const output = await fetch(`/api/module/${id}/output`).then(r=>r.json());
    renderModuleDetail(id, output);
}

async function selectOption(moduleId, optId) {
    selectedOptions[moduleId] = optId;
    const output = await fetch(`/api/module/${moduleId}/output`).then(r=>r.json());
    renderModuleDetail(moduleId, output);
}

async function confirmAndAdvance(moduleId) {
    const nextIdx = MODULES.indexOf(moduleId) + 1;
    if (nextIdx < MODULES.length) {
        const nextId = MODULES[nextIdx];
        await runModule(nextId, null);
        selectedModule = nextId;
    }
}

async function runModuleUI(id) {
    await runModule(id, null);
    await sleep(500);
    await refresh();
}

async function resetAll() {
    if (confirm('确定重置整个工作流？所有数据将清除。')) {
        await resetWorkflow();
        selectedModule = null;
        selectedOptions = {A: null, B: null};
        await refresh();
    }
}

async function startFromA() {
    await runModule('A', null);
    selectedModule = 'A';
    await refresh();
}

async function refresh() {
    state = await fetchState();
    config = await fetchConfig();
    renderPipeline(state);
    renderStageList(state);
    renderConfig(config);
    renderPlatforms(config);
    renderLogs(state.logs);
    if (selectedModule) {
        const output = await fetch(`/api/module/${selectedModule}/output`).then(r=>r.json());
        renderModuleDetail(selectedModule, output);
    }
}

function updateConfig(key, value) {
    updateConfigKey(key, value);
}

async function togglePlatform(p) {
    const cfg = await fetchConfig();
    const sel = cfg.platforms.selected;
    const idx = sel.indexOf(p);
    if (idx >= 0) sel.splice(idx, 1);
    else sel.push(p);
    await fetch('/api/config', {method:'PUT', headers:{'Content-Type':'application/json'}, body: JSON.stringify({platforms: {selected: sel}})});
    await refresh();
}

function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

// Polling for running modules
setInterval(async () => {
    const s = await fetchState();
    let changed = false;
    MODULES.forEach(id => {
        if (s.modules[id].status !== (state.modules[id]?.status)) changed = true;
    });
    if (changed || s.logs?.length !== state.logs?.length) {
        state = s;
        renderPipeline(state);
        renderStageList(state);
        renderLogs(state.logs);
        if (selectedModule) {
            const output = await fetch(`/api/module/${selectedModule}/output`).then(r=>r.json());
            renderModuleDetail(selectedModule, output);
        }
    }
}, 2000);

// Init
refresh();
</script>
