        .stage-item .stage-name { font-size: 12px; font-weight: 500; }
        .stage-item .stage-time { font-size: 10px; color: var(--text-dim); }

        .platform-grid { display: flex; flex-wrap: wrap; gap: 7px; }
        .platform-chip { padding: 5px 12px; border: 1px solid var(--border); border-radius: 16px; font-size: 11px; cursor: pointer; transition: all 0.15s; }
        .platform-chip:hover { border-color: var(--accent); }
        .platform-chip.selected { background: var(--accent); border-color: var(--accent); color: white; }

        @keyframes pulse { 0%,100% { opacity: 1; } 50% { opacity: 0.3; } }
        .running-indicator { animation: pulse 1.5s infinite; }

        .empty-state { text-align: center; padding: 36px 20px; color: var(--text-dim); }
        .empty-state .icon { font-size: 36px; margin-bottom: 10px; }
        .empty-state p { font-size: 12px; }

        @media (max-width: 900px) { .main-grid { grid-template-columns: 1fr; } .config-grid { grid-template-columns: 1fr; } }
    </style>
</head>
<body>
<div class="container">

    <header>
        <div>
            <h1>🎬 创作流水线控制面板</h1>
            <div style="font-size:11px;color:var(--text-dim);margin-top:3px;">模块化AI视频创作工作流</div>
        </div>
        <div class="controls">
            <button class="btn btn-primary" onclick="startFromA()">▶ 从选题开始</button>
            <button class="btn btn-danger" onclick="resetAll()">↺ 重置</button>
            <button class="btn" onclick="refresh()">↻ 刷新</button>
        </div>
    </header>

    <div class="pipeline" id="pipeline"></div>

    <div class="main-grid">
        <div class="left-panel">
            <div class="card">
                <div class="card-title">📋 模块详情</div>
                <div id="module-detail" class="module-detail"></div>
                <div id="module-empty" class="empty-state">
                    <div class="icon">📋</div>
                    <p>点击上方模块查看详情</p>
                </div>
            </div>
        </div>

        <div class="sidebar-right">
            <div class="card">
                <div class="card-title">📊 进度总览</div>
                <div id="stage-list" class="stage-list"></div>
            </div>

            <div class="card">
                <div class="card-title">⚙️ 工具配置</div>
                <div class="config-grid">
                    <div class="config-item">
                        <label>LLM 模型</label>
                        <select id="cfg-llm" onchange="updateConfigKey('llm',this.value)"></select>
                    </div>
                    <div class="config-item">
                        <label>视频生成</label>
                        <select id="cfg-video" onchange="updateConfigKey('video',this.value)"></select>
                    </div>
                    <div class="config-item">
                        <label>语音合成</label>
                        <select id="cfg-audio" onchange="updateConfigKey('audio',this.value)"></select>
                    </div>
                </div>
            </div>

            <div class="card">
                <div class="card-title">📡 发布平台</div>
                <div id="platform-list" class="platform-grid"></div>
            </div>

            <div class="card">
                <div class="card-title">📋 运行日志</div>
                <div id="log-panel" class="log-panel"></div>
            </div>
        </div>
    </div>
</div>

<script>
const MODULE_NAMES = {A:'内容选题',B:'文案创作',C:'合规审查',D:'视频生成',E:'语音合成',F:'内容组装',G:'多平台发布'};
const MODULES = ['A','B','C','D','E','F','G'];
const PLATFORM_NAMES = {douyin:'抖音',kuaishou:'快手',xiaohongshu:'小红书',shipinhao:'视频号',bilibili:'B站'};
let state={}, config={}, selectedModule=null, selectedOptions={A:null,B:null};

async function fetchState(){return fetch('/api/state').then(r=>r.json());}
async function fetchConfig(){return fetch('/api/config').then(r=>r.json());}
async function runModule(id,input){await fetch(`/api/module/${id}/run`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({input})});}
async function resetModule(id){await fetch(`/api/module/${id}/reset`,{method:'POST'});}
async function updateConfigKey(key,value){await fetch('/api/config',{method:'PUT',headers:{'Content-Type':'application/json'},body:JSON.stringify({[key]:{current:value}})});}
async function resetWorkflow(){await fetch('/api/workflow/reset',{method:'POST'});}

function renderPipeline(s){
    document.getElementById('pipeline').innerHTML=MODULES.map(id=>{
        const m=s.modules[id];
        return `<div class="pipeline-item ${selectedModule===id?'active':''}" onclick="selectModule('${id}')">
            <div class="module-id">模块 ${id}</div><div class="module-name">${m.name}</div>
            <span class="status-badge status-${m.status}">${slabel(m.status)}</span>
        </div>`;}).join('');
}
function renderStageList(s){
    let found=false;
    document.getElementById('stage-list').innerHTML=MODULES.map(id=>{
        const m=s.modules[id];
        let cls='pending',label=m.name;
        if(m.status==='done')cls='done';
        else if(m.status==='running'){cls='current';found=true;}
        else if(m.status==='error')cls='error';
        const t=(m.completed_at||m.started_at||'').split('T')[1]?.slice(0,8)||'';
        return `<div class="stage-item" onclick="selectModule('${id}')">
            <div class="stage-num ${cls}">${id}</div>
            <div class="stage-info"><div class="stage-name">${label}</div><div class="stage-time">${t}</div></div>
        </div>`;}).join('');
}
function renderConfig(cfg){
    const llm=document.getElementById('cfg-llm');
    const vid=document.getElementById('cfg-video');
    const aud=document.getElementById('cfg-audio');
    llm.innerHTML=cfg.llm.available.map(k=>`<option value="${k}">${cfg.llm.models[k].name}</option>`).join('');
    vid.innerHTML=cfg.video.available.map(k=>`<option value="${k}">${k}</option>`).join('');
    aud.innerHTML=cfg.audio.available.map(k=>`<option value="${k}">${k}</option>`).join('');
    llm.value=cfg.llm.current;vid.value=cfg.video.current;aud.value=cfg.audio.current;
}
function renderPlatforms(cfg){
    document.getElementById('platform-list').innerHTML=cfg.platforms.available.map(p=>{
        return `<div class="platform-chip ${cfg.platforms.selected.includes(p)?'selected':''}" onclick="togglePlatform('${p}')">${PLATFORM_NAMES[p]||p}</div>`;}).join('');
}
function renderLogs(logs){
    const p=document.getElementById('log-panel');
    if(!logs?.length){p.innerHTML='<div style="color:var(--text-dim);font-size:11px;text-align:center;padding:16px;">暂无日志</div>';return;}
    p.innerHTML=logs.slice(-25).reverse().map(l=>`<div class="log-entry ${l.level}"><span class="time">${l.timestamp.split('T')[1]?.slice(0,8)||''}</span><span class="msg">${l.message}</span></div>`).join('');
}
function slabel(s){return {idle:'待启动',running:'进行中',done:'已完成',error:'错误',paused:'暂停'}[s]||s;}

async function renderModuleDetail(id){
    const detail=document.getElementById('module-detail');
    const empty=document.getElementById('module-empty');
    const m=state.modules[id];
    const out=await fetch(`/api/module/${id}/output`).then(r=>r.json());
    if(!m||m.status==='idle'){detail.classList.remove('active');empty.style.display='block';return;}
    empty.style.display='none';detail.classList.add('active');
    let h=`<div class="module-header"><h3>模块 ${id} — ${MODULE_NAMES[id]}</h3><div class="actions">`;
    if(m.status==='done')h+=`<button class="btn" onclick="resetModule('${id}')">重置</button>`;
    if(m.status==='idle'||m.status==='done'||m.status==='error')h+=`<button class="btn btn-primary" onclick="runModuleUI('${id}')">运行</button>`;
    if(m.status==='running')h+=`<button class="btn" disabled>运行中...</button>`;
    h+=`</div></div>`;

    if(id==='A'&&out.options){
        h+=`<div class="options-list">`;
        out.options.forEach(o=>{h+=`<div class="option-item ${selectedOptions.A===o.id?'selected':''}" onclick="selOpt('A','${o.id}')">
            <div class="option-title">${o.title}</div><div class="option-desc">${o.description}</div>
            <div class="option-meta">${o.type} · ${o.duration}</div></div>`;});
        h+=`</div>`;
        if(selectedOptions.A)h+=`<div style="margin-top:10px;"><button class="btn btn-primary" onclick="confirmAdvance('A')">确认选题 →</button></div>`;
    } else if(id==='B'&&out.options){
        h+=`<div class="options-list">`;
        out.options.forEach(o=>{h+=`<div class="option-item ${selectedOptions.B===o.id?'selected':''}" onclick="selOpt('B','${o.id}')">
            <div class="option-title">${o.title}</div><div class="option-desc">${o.description}</div>
            <div class="option-meta">风格: ${o.style}</div></div>`;});
        h+=`</div>`;
        if(selectedOptions.B)h+=`<div style="margin-top:10px;"><button class="btn btn-primary" onclick="confirmAdvance('B')">确认文案方向 →</button></div>`;
    } else if(id==='C'&&out){
        const risk=out.risk_score||0;
        const rc=risk<30?'var(--success)':risk<60?'var(--warning)':'var(--error)';
        h+=`<div class="compliance-summary ${out.passed?'compliance-pass':'compliance-fail'}">
            <div class="score" style="color:${rc}">${risk}</div><div class="label">风险评分 (0=安全, 100=危险)</div>
            <div style="margin-top:6px;font-size:12px;">${out.summary||''}</div></div>`;
        if(out.issues?.length){h+=`<div style="font-size:12px;font-weight:600;margin-bottom:6px;">❌ 必须修改</div>`;
            out.issues.forEach(i=>{h+=`<div class="issue-item">${i.line||''}: ${i.text} → ${i.suggestion}</div>`;});}
        if(out.warnings?.length){h+=`<div style="font-size:12px;font-weight:600;margin:8px 0 6px;">⚠️ 建议修改</div>`;
            out.warnings.forEach(w=>{h+=`<div class="warning-item">${w.line||''}: ${w.text} → ${w.suggestion}</div>`;});}
        if(out.passed&&!out.issues?.length)h+=`<button class="btn btn-primary" onclick="confirmAdvance('C')">通过 →</button>`;
        else h+=`<button class="btn" onclick="runModuleUI('C')">重新审查</button>`;
    } else if(id==='D'&&out){
        if(out.status==='generated'){h+=`<div class="file-output"><div class="file-icon">🎬</div><div class="file-info">
            <div class="filename">${out.file}</div><div class="filesize">${out.duration} · ${out.style}</div></div></div>
            <div style="margin-top:10px;"><button class="btn btn-primary" onclick="confirmAdvance('D')">确认视频 →</button></div>`;}
        else h+=`<div style="color:var(--text-dim);text-align:center;padding:24px;">正在生成中...</div>`;
    } else if(id==='E'&&out){
        if(out.status==='generated'){h+=`<div class="file-output"><div class="file-icon">🎙️</div><div class="file-info">
            <div class="filename">${out.file}</div><div class="filesize">${out.duration} · ${out.voice}</div></div></div>
            <div style="margin-top:10px;"><button class="btn btn-primary" onclick="confirmAdvance('E')">确认音频 →</button></div>`;}
        else h+=`<div style="color:var(--text-dim);text-align:center;padding:24px;">正在生成中...</div>`;
    } else if(id==='F'&&out){
        if(out.status==='assembled'){h+=`<div class="file-output"><div class="file-icon">🎞</div><div class="file-info">
            <div class="filename">${out.file}</div><div class="filesize">${out.duration}${out.has_subtitle?' · 有字幕':''}${out.has_music?' · 有配乐':''}</div></div></div>
            <div style="margin-top:10px;"><button class="btn btn-primary" onclick="confirmAdvance('F')">确认成片 →</button></div>`;}
    } else if(id==='G'&&out.results){
        out.results.forEach(r=>{h+=`<div class="file-output"><div class="file-icon">${r.status==='published'?'✅':'⏳'}</div><div class="file-info">
            <div class="filename">${PLATFORM_NAMES[r.platform]||r.platform}</div>
            <div class="filesize">${r.status}${r.url!=='#'?' · '+r.url:''}</div></div></div>`;});
    }
    if(m.status==='running')h+=`<div style="margin-top:14px;text-align:center;"><span class="running-indicator">●</span> 运行中...</div>`;
    if(m.status==='error')h+=`<div style="margin-top:14px;color:var(--error);font-size:12px;">❌ 错误: ${m.error_message||'未知'}</div>`;
    detail.innerHTML=h;
}

async function selectModule(id){selectedModule=id;renderPipeline(state);await renderModuleDetail(id);}
async function selOpt(m,oid){selectedOptions[m]=oid;await renderModuleDetail(m);}
async function confirmAdvance(m){const i=MODULES.indexOf(m)+1;if(i<MODULES.length){await runModule(MODULES[i],null);selectedModule=MODULES[i];}refresh();}
async function runModuleUI(id){await runModule(id,null);await sleep(400);refresh();}
async function resetAll(){if(confirm('确定重置整个工作流？所有数据将清除。')){await resetWorkflow();selectedModule=null;selectedOptions={A:null,B:null};refresh();}}
async function startFromA(){await runModule('A',null);selectedModule='A';refresh();}
async function refresh(){state=await fetchState();config=await fetchConfig();renderPipeline(state);renderStageList(state);renderConfig(config);renderPlatforms(config);renderLogs(state.logs);if(selectedModule)await renderModuleDetail(selectedModule);}
async function togglePlatform(p){const cfg=await fetchConfig();const sel=cfg.platforms.selected;const i=sel.indexOf(p);if(i>=0)sel.splice(i,1);else sel.push(p);await fetch('/api/config',{method:'PUT',headers:{'Content-Type':'application/json'},body:JSON.stringify({platforms:{selected:sel}})});refresh();}
function sleep(ms){return new Promise(r=>setTimeout(r,ms));}

setInterval(async()=>{
    const s=await fetchState();
    let ch=MODULES.some(id=>s.modules[id].status!==state.modules?.[id]?.status);
    if(ch||s.logs?.length!==state.logs?.length){state=s;renderPipeline(state);renderStageList(state);renderLogs(state.logs);if(selectedModule)await renderModuleDetail(selectedModule);}
},2000);

refresh();
</script>
</body>
</html>
